export function Original(price, weight, card) {
  var totalPrice = 0;
  var deliveryPrice = 0;

  if (price >= 200) {
    totalPrice = price * 0.9;
  } else if (weight >= 5 && price <= 100) {
    deliveryPrice = weight;
    totalPrice = price;
  } else totalPrice = price;
  if (card) {
    totalPrice = totalPrice * 0.97;
  }
  totalPrice = totalPrice + deliveryPrice;

  if (card && price >= 200 && weight < 5) {
    totalPrice = price * 0.85;
  }
  totalPrice = Math.round((totalPrice + Number.EPSILON) * 10) / 10;
  return totalPrice;
}

